sql:
SELECT tier_id, tier_name 
FROM sponsorship_tiers 
WHERE price = (SELECT MAX(price) FROM sponsorship_tiers);

external_knowledge:
- Benefits are typically offered to sponsors as part of a sponsorship package, and each benefit may be included in multiple sponsorship tiers; 
- Sponsorship tiers are categorized based on the price and the benefits offered; 
- Revenue is generated when a sponsor purchases a sponsorship tier.

sql:
SELECT AVG(price) AS average_price
FROM sponsorship_tiers
WHERE is_active = 1;

SELECT tier_name 
FROM sponsorship_tiers 
WHERE max_companies = (SELECT MAX(max_companies) FROM sponsorship_tiers);

SELECT COUNT(DISTINCT company_id) AS total_companies
FROM sponsorships
WHERE status = 'active';
